// USDC（FiatTokenV2_1）关键代码片段，节选自 Etherscan 已验证源码。
// 完整代码：https://etherscan.io/address/0x43506849D7C04F9138D1A2050bbF3A0c054402dd#code

pragma solidity 0.6.12;

// ===== Ownable =====
contract Ownable {
    address private _owner;
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Ownable: caller is not the owner");
        _;
    }
    function owner() external view returns (address) { return _owner; }
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is zero");
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}

// ===== Pausable =====
contract Pausable is Ownable {
    address public pauser;
    bool public paused = false;
    event Pause();
    event Unpause();
    event PauserChanged(address indexed newAddress);

    modifier whenNotPaused() { require(!paused, "Pausable: paused"); _; }
    modifier onlyPauser() { require(msg.sender == pauser, "Pausable: caller is not the pauser"); _; }

    function pause() external onlyPauser { paused = true; emit Pause(); }
    function unpause() external onlyPauser { paused = false; emit Unpause(); }
    function updatePauser(address newPauser) external onlyOwner {
        require(newPauser != address(0), "Pausable: zero pauser");
        pauser = newPauser; emit PauserChanged(newPauser);
    }
}

// ===== Blacklistable =====
contract Blacklistable is Ownable {
    address public blacklister;
    mapping(address => bool) internal blacklisted;
    event Blacklisted(address indexed _account);
    event UnBlacklisted(address indexed _account);
    event BlacklisterChanged(address indexed newBlacklister);

    modifier onlyBlacklister() { require(msg.sender == blacklister, "caller is not blacklister"); _; }
    modifier notBlacklisted(address _account) { require(!blacklisted[_account], "account blacklisted"); _; }

    function isBlacklisted(address _account) external view returns (bool) { return blacklisted[_account]; }
    function blacklist(address _account) external onlyBlacklister { blacklisted[_account] = true; emit Blacklisted(_account); }
    function unBlacklist(address _account) external onlyBlacklister { blacklisted[_account] = false; emit UnBlacklisted(_account); }
    function updateBlacklister(address _newBlacklister) external onlyOwner {
        require(_newBlacklister != address(0), "Blacklistable: new blacklister is zero");
        blacklister = _newBlacklister; emit BlacklisterChanged(_newBlacklister);
    }
}

// ===== FiatToken V2_1（节选） =====
contract FiatTokenV2_1 is Ownable, Pausable, Blacklistable {
    string public name;
    string public symbol;
    uint8 public decimals;
    string public currency;
    address public masterMinter;

    uint256 internal _totalSupply;
    mapping(address => uint256) internal balances;
    mapping(address => mapping(address => uint256)) internal allowed;

    mapping(address => bool) internal minters;
    mapping(address => uint256) internal minterAllowed;

    event Mint(address indexed minter, address indexed to, uint256 amount);
    event Burn(address indexed burner, uint256 amount);
    event MinterConfigured(address indexed minter, uint256 minterAllowedAmount);
    event MinterRemoved(address indexed oldMinter);
    event MasterMinterChanged(address indexed newMasterMinter);
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    modifier onlyMinters() { require(minters[msg.sender], "caller is not a minter"); _; }

    function totalSupply() external view returns (uint256) { return _totalSupply; }
    function balanceOf(address account) external view returns (uint256) { return balances[account]; }

    function transfer(address to, uint256 value)
        external whenNotPaused notBlacklisted(msg.sender) notBlacklisted(to)
        returns (bool)
    {
        require(to != address(0), "transfer to zero");
        require(value <= balances[msg.sender], "insufficient balance");
        balances[msg.sender] -= value;
        balances[to] += value;
        emit Transfer(msg.sender, to, value);
        return true;
    }

    function approve(address spender, uint256 value)
        external whenNotPaused notBlacklisted(msg.sender) notBlacklisted(spender)
        returns (bool)
    {
        allowed[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }

    function mint(address _to, uint256 _amount)
        external whenNotPaused onlyMinters notBlacklisted(msg.sender) notBlacklisted(_to)
        returns (bool)
    {
        require(_to != address(0), "mint to zero");
        require(_amount > 0, "mint zero amount");
        uint256 mintingAllowedAmount = minterAllowed[msg.sender];
        require(_amount <= mintingAllowedAmount, "exceeds minter allowance");
        _totalSupply += _amount;
        balances[_to] += _amount;
        minterAllowed[msg.sender] = mintingAllowedAmount - _amount;
        emit Mint(msg.sender, _to, _amount);
        emit Transfer(address(0), _to, _amount);
        return true;
    }

    function burn(uint256 _amount) external whenNotPaused onlyMinters notBlacklisted(msg.sender) {
        uint256 balance = balances[msg.sender];
        require(_amount > 0, "burn zero");
        require(balance >= _amount, "insufficient balance");
        _totalSupply -= _amount;
        balances[msg.sender] = balance - _amount;
        emit Burn(msg.sender, _amount);
        emit Transfer(msg.sender, address(0), _amount);
    }

    function configureMinter(address minter, uint256 minterAllowedAmount)
        external whenNotPaused returns (bool)
    {
        require(msg.sender == masterMinter, "only masterMinter");
        minters[minter] = true;
        minterAllowed[minter] = minterAllowedAmount;
        emit MinterConfigured(minter, minterAllowedAmount);
        return true;
    }

    function updateMasterMinter(address _newMasterMinter) external onlyOwner {
        require(_newMasterMinter != address(0), "new masterMinter zero");
        masterMinter = _newMasterMinter;
        emit MasterMinterChanged(_newMasterMinter);
    }

    // ===== 注意：本合约还有 EIP-3009 (transferWithAuthorization) 与 EIP-2612 (permit) 实现 =====
    // ===== 这里截取核心，省略链下签名验证细节 =====
}

